import { useState } from "react";

export default function LoginPage() {
  const [showPassword, setShowPassword] = useState(false);

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-purple-600 to-indigo-700 px-4">
      <div className="max-w-md w-full bg-white rounded-xl shadow-lg p-8 space-y-6">
        {/* Logo & Welcome */}
        <div className="text-center">
          <div className="text-3xl font-bold text-gray-800">Welcome Back</div>
          <p className="text-sm text-gray-500 mt-1">
            Please enter your details to sign in
          </p>
        </div>

        {/* Social Login */}
        <div className="flex justify-center space-x-4">
          <button className="bg-gray-100 p-2 rounded-full hover:bg-gray-200">
            <img src="/google-icon.svg" alt="Google" className="w-6 h-6" />
          </button>
          <button className="bg-gray-100 p-2 rounded-full hover:bg-gray-200">
            <img src="/facebook-icon.svg" alt="Facebook" className="w-6 h-6" />
          </button>
          <button className="bg-gray-100 p-2 rounded-full hover:bg-gray-200">
            <img src="/github-icon.svg" alt="GitHub" className="w-6 h-6" />
          </button>
        </div>

        {/* Divider */}
        <div className="flex items-center">
          <div className="flex-grow h-px bg-gray-300" />
          <span className="px-2 text-sm text-gray-400">or</span>
          <div className="flex-grow h-px bg-gray-300" />
        </div>

        {/* Form */}
        <form className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700">
              Email address*
            </label>
            <input
              type="email"
              placeholder="Enter your email address"
              className="mt-1 w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-purple-500"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700">
              Password*
            </label>
            <div className="relative">
              <input
                type={showPassword ? "text" : "password"}
                placeholder="••••••••"
                className="mt-1 w-full px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-purple-500"
                required
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-3 text-gray-500 hover:text-gray-700">
                👁️
              </button>
            </div>
          </div>

          <div className="flex items-center justify-between text-sm">
            <label className="flex items-center space-x-2">
              <input type="checkbox" className="form-checkbox" />
              <span>Remember Me</span>
            </label>
            <a href="#" className="text-purple-600 hover:underline">
              Forgot Password?
            </a>
          </div>

          <button
            type="submit"
            className="w-full bg-purple-600 text-white py-2 rounded-md hover:bg-purple-700 transition">
            Sign in to FlyonUI
          </button>
        </form>

        {/* Footer */}
        <div className="text-center text-sm text-gray-600">
          New on our platform?{" "}
          <a href="#" className="text-purple-600 hover:underline">
            Create an account
          </a>
        </div>
      </div>
    </div>
  );
}
